const body = $input.first().json.body || $input.first().json;
const newStatus = (body.history_items?.[0]?.after?.status || body.status?.status || '').toLowerCase().trim();
const folderId = (body.task?.folder?.id || '').toString();
const taskId = body.task_id || body.task?.id || '';
const eFechamento = newStatus === 'contrato fechado';
const eCRM = folderId === '90117445648' || folderId === '';
return [{ json: { prosseguir: eFechamento && eCRM && taskId !== '', taskId, newStatus } }];

const task = $input.first().json;
const cf = task.custom_fields || [];
function getField(id) {
  const f = cf.find(x => x.id === id);
  if (!f) return '';
  if (f.type_config?.options) {
    const opt = f.type_config.options.find(o => o.orderindex === f.value || o.id === f.value);
    return opt?.name || f.value || '';
  }
  return (f.value || '').toString();
}
function getByName(frag) {
  const f = cf.find(x => (x.name||'').toLowerCase().includes(frag.toLowerCase()) && x.value);
  if (!f) return '';
  if (f.type_config?.options) {
    const opt = f.type_config.options.find(o => o.orderindex === f.value || o.id === f.value);
    return opt?.name || f.value || '';
  }
  return (f.value || '').toString();
}
const origem = getField('2cf330fd-8a82-4378-81de-27b83e6375d3') || getByName('origem');
const gclid = getField('7768805a-8c36-4201-90c7-d9ee3f2eb6c3') || getByName('gclid');
const campanha = getField('b236bc57-b08b-44bc-9b3b-7f88950c4c91') || getByName('campanha');
const eGoogle = origem.toLowerCase().includes('google') || origem.toLowerCase().includes('ads') || gclid !== '';
const closer = task.assignees?.[0]?.username || task.assignees?.[0]?.email || 'não informado';
const dataFechamento = task.date_done ? new Date(parseInt(task.date_done)).toLocaleDateString('pt-BR',{timeZone:'America/Sao_Paulo'}) : new Date().toLocaleDateString('pt-BR',{timeZone:'America/Sao_Paulo'});
return [{ json: { eGoogle, taskId: task.id, nome: task.name, taskUrl: task.url, telefone: getField('dd097c3b-5647-4535-9847-1026f6ea70c0') || 'não informado', email: getByName('email') || getByName('e-mail') || 'não informado', origem: origem || 'não informado', canal: getByName('canal') || 'não informado', closer, dataFechamento, valorContrato: getByName('valor') || getByName('honorário') || 'não informado', gclid: gclid || 'não informado', utmSource: getByName('utm_source') || (gclid ? 'google' : 'não informado'), utmCampaign: campanha || 'não informado' } }];

